import{_ as e,o as i,c as a,ak as r}from"./chunks/framework.DwHlt8HN.js";const f=JSON.parse('{"title":"UUID","description":"XW37-BLE module Bluetooth UUIDs","frontmatter":{"title":"UUID","description":"XW37-BLE module Bluetooth UUIDs"},"headers":[],"relativePath":"docs/ble-stack/uuid.md","filePath":"docs/ble-stack/uuid.md"}'),s={name:"docs/ble-stack/uuid.md"};function o(l,t,d,c,n,h){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="uuid-configuration" tabindex="-1">UUID Configuration <a class="header-anchor" href="#uuid-configuration" aria-label="Permalink to “UUID Configuration”">​</a></h1><h2 id="service-and-characteristics" tabindex="-1">Service and Characteristics <a class="header-anchor" href="#service-and-characteristics" aria-label="Permalink to “Service and Characteristics”">​</a></h2><p>The XW37-BLE module uses the following BLE UUIDs for communication:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">UUID</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Service UUID</strong></td><td style="text-align:left;"><code>0xFFB0</code></td><td style="text-align:left;">Primary BLE service</td></tr><tr><td style="text-align:left;"><strong>Characteristic 1</strong></td><td style="text-align:left;"><code>0xFFB1</code></td><td style="text-align:left;">Write Without Response</td></tr><tr><td style="text-align:left;"><strong>Characteristic 2</strong></td><td style="text-align:left;"><code>0xFFB2</code></td><td style="text-align:left;">Read Notify</td></tr></tbody></table><h2 id="uuid-details" tabindex="-1">UUID Details <a class="header-anchor" href="#uuid-details" aria-label="Permalink to “UUID Details”">​</a></h2><h3 id="service-uuid-0xffb0" tabindex="-1">Service UUID (0xFFB0) <a class="header-anchor" href="#service-uuid-0xffb0" aria-label="Permalink to “Service UUID (0xFFB0)”">​</a></h3><p>The primary service UUID that identifies the XW37-BLE module&#39;s BLE service.</p><h3 id="characteristic-0xffb1-write-without-response" tabindex="-1">Characteristic 0xFFB1 - Write Without Response <a class="header-anchor" href="#characteristic-0xffb1-write-without-response" aria-label="Permalink to “Characteristic 0xFFB1 - Write Without Response”">​</a></h3><p>Allows the connected device to send data to the module without requiring a response. Used for:</p><ul><li>Sending commands to the module</li><li>Transmitting data from App to MCU</li></ul><h3 id="characteristic-0xffb2-read-notify" tabindex="-1">Characteristic 0xFFB2 - Read Notify <a class="header-anchor" href="#characteristic-0xffb2-read-notify" aria-label="Permalink to “Characteristic 0xFFB2 - Read Notify”">​</a></h3><p>Supports:</p><ul><li>Reading data from the module</li><li>Receiving notifications from the module</li><li>Receiving data from the module (MCU to App)</li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>These UUIDs are used for BLE communication between the module and connected devices (Apps, master devices, etc.).</p></div>',14)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
